    portLabel: '\u7AEF\u53E3', portLabelTip: '\u670D\u52A1\u5668\u76D1\u542C\u7684\u7F51\u7EDC\u7AEF\u53E3',
    apiKey: 'API \u5BC6\u94A5', apiKeyTip: 'API \u5BC6\u94A5\uFF0C\u7528\u4E8E\u4EE4\u724C\u8BA4\u8BC1\uFF08\u53EF\u9009\uFF09',
    apiKeyFile: 'API \u5BC6\u94A5\u6587\u4EF6', apiKeyFileTip: '\u4ECE\u6587\u4EF6\u8BFB\u53D6 API \u5BC6\u94A5\uFF0C\u800C\u975E\u76F4\u63A5\u8F93\u5165',
